package test.rice.test;

import main.rice.obj.*;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.io.TempDir;
import java.io.*;
import java.nio.file.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Agent tests for Tester, TestCase, and TestResults edge cases.
 */
class AgentTesterTest {

    @TempDir
    Path tempDir;

    private Path solutionDir;
    private Path implDir;

    @BeforeEach
    void setUp() throws IOException {
        solutionDir = tempDir.resolve("solution");
        implDir = tempDir.resolve("impl");
        Files.createDirectories(solutionDir);
        Files.createDirectories(implDir);
    }

    // =====================================================
    // Helper methods
    // =====================================================

    private Path createAddSolution() throws IOException {
        Path solutionFile = solutionDir.resolve("solution.py");
        String content = "def add(a, b):\n    return a + b\n";
        Files.writeString(solutionFile, content);
        return solutionFile;
    }

    private Path createIdentitySolution() throws IOException {
        Path solutionFile = solutionDir.resolve("solution.py");
        String content = "def identity(x):\n    return x\n";
        Files.writeString(solutionFile, content);
        return solutionFile;
    }

    private void createCorrectAddImpl(String filename) throws IOException {
        String content = "def add(a, b):\n    return a + b\n";
        Files.writeString(implDir.resolve(filename), content);
    }

    private void createBuggyAddImpl(String filename) throws IOException {
        String content = "def add(a, b):\n    return 0\n";
        Files.writeString(implDir.resolve(filename), content);
    }

    private List<TestCase> createAddTestCases() {
        return Arrays.asList(
            new TestCase(Arrays.asList(new PyIntObj(1), new PyIntObj(2))),
            new TestCase(Arrays.asList(new PyIntObj(3), new PyIntObj(4))),
            new TestCase(Arrays.asList(new PyIntObj(0), new PyIntObj(0)))
        );
    }

    // =====================================================
    // TestCase edge cases
    // =====================================================

    @Test
    void testCaseEqualsNull() {
        TestCase tc = new TestCase(Arrays.asList(new PyIntObj(1)));
        assertNotEquals(null, tc);
    }

    @Test
    void testCaseEqualsNonTestCase() {
        TestCase tc = new TestCase(Arrays.asList(new PyIntObj(1)));
        assertNotEquals("not a test case", tc);
    }

    @Test
    void testCaseEqualsSameArgs() {
        TestCase tc1 = new TestCase(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        TestCase tc2 = new TestCase(Arrays.asList(new PyIntObj(1), new PyIntObj(2)));
        assertEquals(tc1, tc2);
        assertEquals(tc1.hashCode(), tc2.hashCode());
    }

    @Test
    void testCaseNotEqualsDifferentArgs() {
        TestCase tc1 = new TestCase(Arrays.asList(new PyIntObj(1)));
        TestCase tc2 = new TestCase(Arrays.asList(new PyIntObj(2)));
        assertNotEquals(tc1, tc2);
    }

    @Test
    void testCaseToStringOneArg() {
        TestCase tc = new TestCase(Arrays.asList(new PyIntObj(42)));
        assertEquals("[42]", tc.toString());
    }

    @Test
    void testCaseToStringMultipleArgs() {
        TestCase tc = new TestCase(Arrays.asList(
            new PyIntObj(1), new PyStringObj("hi"), new PyFloatObj(2.5)));
        assertEquals("[1, 'hi', 2.5]", tc.toString());
    }

    // =====================================================
    // TestResults edge cases
    // =====================================================

    @Test
    void testGetTestCaseNegativeIndex() {
        TestCase tc = new TestCase(Arrays.asList(new PyIntObj(1)));
        TestResults results = new TestResults(
            Arrays.asList(tc),
            Arrays.asList(new HashSet<>()),
            new HashSet<>());
        assertNull(results.getTestCase(-1));
    }

    @Test
    void testGetTestCaseOutOfBounds() {
        TestCase tc = new TestCase(Arrays.asList(new PyIntObj(1)));
        TestResults results = new TestResults(
            Arrays.asList(tc),
            Arrays.asList(new HashSet<>()),
            new HashSet<>());
        assertNull(results.getTestCase(1));
        assertNull(results.getTestCase(100));
    }

    @Test
    void testGetTestCaseFirstAndLast() {
        TestCase tc0 = new TestCase(Arrays.asList(new PyIntObj(1)));
        TestCase tc1 = new TestCase(Arrays.asList(new PyIntObj(2)));
        TestCase tc2 = new TestCase(Arrays.asList(new PyIntObj(3)));
        TestResults results = new TestResults(
            Arrays.asList(tc0, tc1, tc2),
            Arrays.asList(new HashSet<>(), new HashSet<>(), new HashSet<>()),
            new HashSet<>());
        assertEquals(tc0, results.getTestCase(0));
        assertEquals(tc2, results.getTestCase(2));
    }

    // =====================================================
    // Tester: runTests with single correct file
    // =====================================================

    @Test
    void testRunTestsSingleCorrectFile() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        createCorrectAddImpl("impl1.py");
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        assertTrue(results.getWrongSet().isEmpty());
        for (Set<Integer> files : results.getCaseToFiles()) {
            assertTrue(files.isEmpty());
        }
    }

    // =====================================================
    // Tester: runTests with single buggy file
    // =====================================================

    @Test
    void testRunTestsSingleBuggyFile() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        createBuggyAddImpl("impl1.py");
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // The buggy impl returns 0 for all inputs; only add(0,0)=0 is correct
        assertTrue(results.getWrongSet().contains(0));
        // Test case 0: add(1,2)=3, buggy returns 0 → caught
        assertTrue(results.getCaseToFiles().get(0).contains(0));
        // Test case 1: add(3,4)=7, buggy returns 0 → caught
        assertTrue(results.getCaseToFiles().get(1).contains(0));
        // Test case 2: add(0,0)=0, buggy returns 0 → passes
        assertFalse(results.getCaseToFiles().get(2).contains(0));
    }

    // =====================================================
    // Tester: runTests with mixed correct/buggy files
    // =====================================================

    @Test
    void testRunTestsMixedFiles() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        createCorrectAddImpl("aaa_correct.py");
        createBuggyAddImpl("bbb_buggy.py");
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // File 0 (aaa_correct) should pass all
        assertFalse(results.getWrongSet().contains(0));
        // File 1 (bbb_buggy) should fail some
        assertTrue(results.getWrongSet().contains(1));
    }

    // =====================================================
    // Tester: skips non-.py files
    // =====================================================

    @Test
    void testRunTestsSkipsNonPyFiles() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        createCorrectAddImpl("impl1.py");
        // Create a non-py file
        Files.writeString(implDir.resolve("readme.txt"), "not python");
        Files.writeString(implDir.resolve("data.csv"), "1,2,3");
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Should only have tested the .py file, which is correct
        assertTrue(results.getWrongSet().isEmpty());
    }

    // =====================================================
    // Tester: handles malformed Python file
    // =====================================================

    @Test
    void testRunTestsMalformedPyFile() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        // Create a malformed Python file (syntax error)
        Files.writeString(implDir.resolve("malformed.py"), "def add(a, b):\n    return a +\n");
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Malformed file should be in wrong set (crashes = not "True")
        assertTrue(results.getWrongSet().contains(0));
    }

    // =====================================================
    // Tester: computeExpectedResults multiple test cases
    // =====================================================

    @Test
    void testComputeExpectedResultsMultipleTests() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        List<String> results = tester.computeExpectedResults();

        assertEquals(3, results.size());
        assertEquals("3", results.get(0));  // 1+2
        assertEquals("7", results.get(1));  // 3+4
        assertEquals("0", results.get(2));  // 0+0
    }

    // =====================================================
    // Tester: partially buggy impl (fails some tests, passes others)
    // =====================================================

    @Test
    void testRunTestsPartiallyBuggy() throws IOException, InterruptedException {
        Path solutionFile = createAddSolution();
        // Works only when a == 1
        String content = "def add(a, b):\n    if a == 1:\n        return a + b\n    return 0\n";
        Files.writeString(implDir.resolve("partial.py"), content);
        List<TestCase> tests = createAddTestCases();
        Tester tester = new Tester("add", solutionFile.toString(), implDir.toString(), tests);

        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // File 0 should be in wrongSet
        assertTrue(results.getWrongSet().contains(0));
        // Test 0: add(1,2) should pass (a==1)
        assertFalse(results.getCaseToFiles().get(0).contains(0));
        // Test 1: add(3,4) should fail (a!=1)
        assertTrue(results.getCaseToFiles().get(1).contains(0));
        // Test 2: add(0,0) returns 0 which matches expected → passes
        assertFalse(results.getCaseToFiles().get(2).contains(0));
    }
}

